import{_ as t}from"./chunks/logo.PPNoggWL.js";import{_ as i,o as a,c as e,ag as o}from"./chunks/framework.wGDfT7ie.js";const k=JSON.parse('{"title":"Installation Troubleshooting Guide","description":"","frontmatter":{"layout":"doc","next":{"text":"Configuration Introduction","link":"/pages/configurations/index"},"prev":{"text":"Updating AtmosphericX","link":"/pages/installation/updating-atmosphericx"}},"headers":[],"relativePath":"pages/installation/troubleshooting.md","filePath":"pages/installation/troubleshooting.md"}'),n={name:"pages/installation/troubleshooting.md"};function l(r,s,d,p,h,c){return a(),e("div",null,[...s[0]||(s[0]=[o('<img src="'+t+`" alt="AtmosphericX Logo" width="200" style="display:block;margin:0 auto;"><small class="page-author">Written By: <b>KiyoWx</b></small><br><small class="last-updated">Last Updated: <b>Feb 27th, 2026</b></small><br><small class="version-made">Version: <b>8.0.0.02 (beta-pre-dashboard-testing)</b></small><br><br><h1 id="installation-troubleshooting-guide" tabindex="-1">Installation Troubleshooting Guide <a class="header-anchor" href="#installation-troubleshooting-guide" aria-label="Permalink to &quot;Installation Troubleshooting Guide&quot;">​</a></h1><p>If you followed the Installation Guide but encounter issues, this troubleshooting section addresses the most common problems. For problems not listed here, join our <a href="https://discord.gg/YAEjtzU3E8" target="_blank" rel="noreferrer">Discord server</a> and provide detailed information. Support is community based and mostly volunteer.</p><div class="tip custom-block"><p class="custom-block-title">Before you troubleshoot</p><p>Confirm that you completed every step in the <a href="./installation.html">Installation Guide</a>. This list mainly addresses Windows issues; macOS and Linux users may not encounter all problems.</p></div><h2 id="common-issues-and-solutions" tabindex="-1">Common Issues and Solutions <a class="header-anchor" href="#common-issues-and-solutions" aria-label="Permalink to &quot;Common Issues and Solutions&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">VS not looking for VS2017 (<a href="https://github.com/AtmosphericX/AtmosphericX/issues/61" target="_blank" rel="noreferrer">Issue #61</a>)</p><p>The installer cannot find Visual C++ Redistributable for Visual Studio 2017 or later.</p><p><strong>Solution:</strong></p><ol><li>Download the latest Redistributable: <a href="https://learn.microsoft.com/en-us/cpp/windows/latest-supported-vc-redist?view=msvc-170" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/cpp/windows/latest-supported-vc-redist?view=msvc-170</a></li><li>Install the correct version for your system (x64 / x86).</li><li>Re-run the installation.</li></ol><blockquote><p>Tip: If <code>better-sqlite3</code> fails, see <a href="https://github.com/WiseLibs/better-sqlite3/blob/master/docs/troubleshooting.md" target="_blank" rel="noreferrer">its troubleshooting guide</a>.</p></blockquote></div><div class="danger custom-block"><p class="custom-block-title">Python not found during installation</p><p>During the installation, the process fails because it cannot find Python 3.8 or newer. Please ensure Python is installed and added to your system PATH.</p><ol><li>Install <strong>Python 3.8 or newer</strong> from:<br><a href="https://www.python.org/downloads/" target="_blank" rel="noreferrer">https://www.python.org/downloads/</a></li><li>During installation, ensure <strong>“Add Python to PATH”</strong> is checked.</li><li>Open a new terminal and verify Python is available:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># or...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div></li><li>Re-run the AtmosphericX installation.</li></ol></div><div class="danger custom-block"><p class="custom-block-title">3. Port 80 already in use</p><p>When starting AtmosphericX, it fails to bind to port 80 because another application is already using it or insufficient permissions.</p><ol><li>Identify the application using port 80:</li></ol><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-SptR1" id="tab-XK_SxI3" checked><label data-title="Windows" for="tab-XK_SxI3">Windows</label><input type="radio" name="group-SptR1" id="tab-kVCIUcj"><label data-title="Linux/macOS" for="tab-kVCIUcj">Linux/macOS</label><input type="radio" name="group-SptR1" id="tab-2waZBda"><label data-title="Linux Elevated Start" for="tab-2waZBda">Linux Elevated Start</label></div><div class="blocks"><div class="language-sh vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">netstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -aon</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> findstr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :80</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lsof</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :80</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-tools</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run.sh</span></span></code></pre></div><ol start="2"><li>Stop the conflicting application or change its port.</li></ol></div></div></div><div class="danger custom-block"><p class="custom-block-title">4. Instant Closure on Start</p><p>AtmosphericX starts but immediately exits without errors. Run AtmosphericX from a terminal to instead of double-clicking the script. This way, you can see any error messages.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><ol start="2"><li>Check the terminal output for errors and address them accordingly.</li><li>If the issue persists, consider reaching out on our <a href="https://discord.gg/YAEjtzU3E8" target="_blank" rel="noreferrer">Discord server</a> for further assistance. Please make sure to include any error logs or messages you encounter.</li></ol></div><h2 id="quick-fix-tldr" tabindex="-1">Quick fix (TLDR) <a class="header-anchor" href="#quick-fix-tldr" aria-label="Permalink to &quot;Quick fix (TLDR)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Quick Fix</th></tr></thead><tbody><tr><td>VS Redistributable</td><td>Install latest VS2017+ Redistributable</td></tr><tr><td>Python missing</td><td>Install Python 3.8+, add to PATH</td></tr><tr><td>Port 80 in use</td><td>Stop conflicting app or change port</td></tr><tr><td>Instant closure</td><td>Run from terminal, check errors</td></tr></tbody></table>`,18)])])}const b=i(n,[["render",l]]);export{k as __pageData,b as default};
